import React, { useState } from 'react';
import "./Dashboard.css";

import {
  Cloud,
  Sprout,
  ShoppingBag,
  Building2,
  Map,
  FileBarChart,
  TrendingUp,
  TrendingDown,
  Phone,
  Send,
  ChevronRight,
  ArrowRight
} from 'lucide-react';

const marketPrices = [
  {
    icon:'🌾',
    name:'Rice',
    price:'₹2800 / Quintal',
    change:'+2.5%',
    up:true
  },

  {
    icon:'🍅',
    name:'Tomato',
    price:'₹32 / Kg',
    change:'-1.2%',
    up:false
  },

  {
    icon:'🧅',
    name:'Onion',
    price:'₹28 / Kg',
    change:'-0.8%',
    up:false
  },

  {
    icon:'🌿',
    name:'Cotton',
    price:'₹7600 / Quintal',
    change:'+1.5%',
    up:true
  }
];

const forecast = [

{
day:'Today',
icon:'⛅',
temp:'31°C',
rain:'20%'
},

{
day:'Tomorrow',
icon:'🌧️',
temp:'30°C',
rain:'40%'
},

{
day:'Monday',
icon:'☀️',
temp:'33°C',
rain:'10%'
},

{
day:'Tuesday',
icon:'☀️',
temp:'34°C',
rain:'0%'
}

];

const schemes = [

{
icon:'👨‍🌾',
name:'PM Kisan Samman Nidhi',
desc:'Direct income support',
color:'#fff3e0',
border:'#ff9800'
},

{
icon:'🛡️',
name:'PM Fasal Bima Yojana',
desc:'Crop insurance',
color:'#e8f5e9',
border:'#4caf50'
},

{
icon:'💧',
name:'PM Krishi Sinchai',
desc:'Irrigation support',
color:'#e3f2fd',
border:'#2196f3'
},

{
icon:'💳',
name:'Kisan Credit Card',
desc:'Easy farmer credit',
color:'#f3e5f5',
border:'#9c27b0'
}

];

const quickActions = [

{
icon:Cloud,
label:'Weather',
color:'#3b82f6'
},

{
icon:Sprout,
label:'Crop Advisor',
color:'#22c55e'
},

{
icon:ShoppingBag,
label:'Market Prices',
color:'#f59e0b'
},

{
icon:Building2,
label:'Government Schemes',
color:'#8b5cf6'
},

{
icon:FileBarChart,
label:'Reports',
color:'#06b6d4'
},

{
icon:Map,
label:'Maps',
color:'#ef4444'
}

];

export default function Dashboard({setActivePage}){

const [chatInput,setChatInput]=useState('');

const [chatMessages,setChatMessages]=useState([]);

function handleSend(){

if(!chatInput.trim()) return;

let reply='';

const q=chatInput.toLowerCase();

if(q.includes('rice')){

reply='Rice needs NPK fertilizer.';

}

else if(q.includes('cotton')){

reply='Cotton grows well in warm weather.';

}

else if(q.includes('rain')){

reply='Tomorrow rain probability is 40%.';

}

else if(q.includes('fertilizer')){

reply='Organic fertilizer is recommended.';

}

else{

reply='Please ask another farming question.';

}

setChatMessages(prev=>[

...prev,

{
text:chatInput,
user:true
},

{
text:reply,
user:false
}

]);

setChatInput('');

}

return(

<div className='dashboard-layout'>

<div className='dashboard-main'>
  <div className="card">

<h2>⚡ Quick Actions</h2>

<div className="quick-actions-grid">

{quickActions.map(({icon:Icon,label})=>(

<button

key={label}

className="quick-action-btn"

onClick={()=>setActivePage(label)}

>

<Icon size={28}/>

<span>{label}</span>

</button>

))}

</div>

</div>

<div className='hero-banner'>

<div className='hero-overlay'>

<div className='hero-badge'>

🤖 AI Powered Digital Agriculture

</div>

<h1 className='hero-title'>

Empowering Every Farmer Digitally

</h1>

<p className='hero-sub'>

Weather • Market Prices • AI Assistant • Government Schemes

</p>

<div className='hero-actions'>

<button

className='btn-primary'

onClick={()=>setActivePage('Weather')}

>

🌦️ Weather

</button>

<button

className='btn-secondary'

onClick={()=>setActivePage('Government Schemes')}

>

🏛️ Schemes

</button>

</div>

</div>

<div className='hero-image-overlay'></div>

</div>

<div className='stats-row'>

<div className='stat-card'>

<div className='stat-icon weather-icon'>

⛅

</div>

<div>

<div className='stat-label'>

Weather

</div>

<div className='stat-value blue'>

31°C

</div>

<div className='stat-sub'>

Partly Cloudy

</div>

</div>

</div>

<div className='stat-card'>

<div className='stat-icon crop-icon'>

🌱

</div>

<div>

<div className='stat-label'>

Crop

</div>

<div className='stat-value green'>

Rice

</div>

<div className='stat-sub'>

Recommended

</div>

</div>

</div>

<div className='stat-card'>

<div className='stat-icon price-icon'>

💰

</div>

<div>

<div className='stat-label'>

Market Price

</div>

<div className='stat-value green'>

₹2800

</div>

<div className='stat-sub'>

Rice

</div>

</div>

</div>

<div className='stat-card'>

<div className='stat-icon scheme-icon'>

🏛️

</div>

<div>

<div className='stat-label'>

Schemes

</div>

<div className='stat-value purple'>

4 Active

</div>

<div className='stat-sub'>

Available

</div>

</div>

</div>

</div>

</div>

<div className='right-panel'>

<div className='panel-card'>

<h3>

AI Assistant

</h3>

<div className='chat-messages'>

{chatMessages.map((msg,index)=>(

<div

key={index}

className={`chat-msg ${msg.user ? 'user-msg' : 'bot-msg'}`}

>

{msg.text}

</div>

))}

</div>

<div className='ai-input-row'>

<input

type='text'

placeholder='Ask farming question'

value={chatInput}

onChange={(e)=>setChatInput(e.target.value)}

onKeyDown={(e)=>e.key==='Enter' && handleSend()}

/>

<button

className='send-btn'

onClick={handleSend}

>

<Send size={14}/>

</button>

</div>

</div>

</div>

</div>

);

}
